// src/utils/workspace/invokePanelView.tsx
async function invokeView(plugin, panel_type, reveal = true) {
  const workspace = plugin.app.workspace;
  await new Promise((resolve) => workspace.onLayoutReady(resolve));
  const leaves = workspace.getLeavesOfType(panel_type);
  let leaf = null;
  if (leaves.length > 0) {
    leaf = leaves[0];
  } else {
    leaf = workspace.getRightLeaf(false);
    if (leaf) {
      await leaf.setViewState(
        { type: panel_type, active: true }
      );
    }
  }
  if (leaf && reveal) {
    await plugin.app.workspace.revealLeaf(leaf);
  }
  return leaf;
}

