function getItemTag(item) {
  return item.data.tag;
}
function getItemLine(item) {
  switch (item.type) {
    case "equation":
      return item.data.lineStart;
    case "figure":
      return item.data.line;
    case "callout":
      return item.data.lineStart;
  }
}
function getItemLineRange(item) {
  switch (item.type) {
    case "equation":
      return { lineStart: item.data.lineStart, lineEnd: item.data.lineEnd };
    case "figure":
      return { lineStart: item.data.line, lineEnd: item.data.line };
    case "callout":
      return { lineStart: item.data.lineStart, lineEnd: item.data.lineEnd };
  }
}
function getItemSearchableContent(item) {
  switch (item.type) {
    case "equation":
      return item.data.content + (item.data.tag || "");
    case "figure":
      return (item.data.title || "") + (item.data.desc || "") + (item.data.tag || "");
    case "callout":
      return item.data.content + (item.data.tag || "") + (item.data.title || "");
  }
}

// src/utils/misc/hash_utils.tsx
function fastHash(str) {
  let hash = 2166136261;
  let i = 0;
  const len = str.length;
  while (i + 3 < len) {
    hash ^= str.charCodeAt(i) | str.charCodeAt(i + 1) << 8 | str.charCodeAt(i + 2) << 16 | str.charCodeAt(i + 3) << 24;
    hash = hash * 16777619 >>> 0;
    i += 4;
  }
  while (i < len) {
    hash ^= str.charCodeAt(i);
    hash = hash * 16777619 >>> 0;
    i++;
  }
  return hash;
}
function hashPanelItems(items) {
  const str = items.map((item) => {
    const lineRange = getItemLineRange(item);
    return `${item.type}|${item.data.raw}|${lineRange.lineStart}|${lineRange.lineEnd}`;
  }).join(";");
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const chr = str.charCodeAt(i);
    hash = (hash << 5) - hash + chr;
    hash |= 0;
  }
  return hash.toString();
}

