async function scrollToEquationByTag(plugin, tag, filePath) {
  const targetFilePath = filePath || plugin.app.workspace.getActiveFile()?.path;
  if (!targetFilePath) {
    Debugger.log("No file path available for scrolling");
    return;
  }
  const normalizedPath = (0, import_obsidian16.normalizePath)(targetFilePath);
  const file = plugin.app.vault.getAbstractFileByPath(normalizedPath);
  if (!(file instanceof import_obsidian16.TFile)) {
    Debugger.log("File not found: " + normalizedPath);
    return;
  }
  const md = await plugin.app.vault.cachedRead(file);
  const match = parseFirstEquationInMarkdown(md, tag, plugin.settings.enableTypstMode);
  if (!match) {
    Debugger.log("Can't find equation with tag: " + tag + " in file: " + normalizedPath);
    return;
  }
  const lineStart = match.lineStart;
  const view = plugin.app.workspace.getActiveViewOfType(import_obsidian16.MarkdownView);
  if (!view?.editor) {
    Debugger.log("Can't find active view or editor");
    return;
  }
  const editor = view.editor;
  const tryScroll = (retries = 5) => {
    if (editor.lineCount() >= lineStart) {
      editor.setCursor({ line: lineStart, ch: 0 });
      const scrollRange = {
        from: { line: lineStart, ch: 0 },
        to: { line: lineStart, ch: 0 }
      };
      editor.scrollIntoView(scrollRange, true);
    } else if (retries > 0) {
      Debugger.log(`Line count ${editor.lineCount()} is less than lineStart ${lineStart}, retrying...`);
      activeWindow.setTimeout(() => {
        tryScroll(retries - 1);
      }, 350);
    } else if (retries === 0) {
      Debugger.log(`Failed to scroll to line ${lineStart} in file ${normalizedPath}`);
    }
  };
  tryScroll();
}
function findLeafWithFile(plugin, filePath, excludeLeaf) {
  const leaves = plugin.app.workspace.getLeavesOfType("markdown");
  for (const leaf of leaves) {
    if (excludeLeaf && leaf === excludeLeaf) {
      continue;
    }
    const view = leaf.view;
    if (view instanceof import_obsidian16.MarkdownView && view.file?.path === filePath) {
      return leaf;
    }
  }
  return null;
}
async function openFileAndScrollToEquation(plugin, sourcePath, tag, openInSplit, currentLeaf) {
  const normalizedSourcePath = (0, import_obsidian16.normalizePath)(sourcePath);
  let targetLeaf = null;
  if (openInSplit) {
    const existingLeaf = findLeafWithFile(plugin, normalizedSourcePath, currentLeaf);
    if (existingLeaf) {
      targetLeaf = existingLeaf;
      Debugger.log("Reusing existing panel (not current) for file: " + normalizedSourcePath);
    } else {
      targetLeaf = plugin.app.workspace.getLeaf("split");
      Debugger.log("Creating new split pane on right for file: " + normalizedSourcePath);
    }
  } else {
    targetLeaf = currentLeaf || plugin.app.workspace.getLeaf(false);
  }
  if (!targetLeaf) {
    Debugger.log("Failed to get target leaf");
    return;
  }
  plugin.app.workspace.setActiveLeaf(targetLeaf, { focus: true });
  await plugin.app.workspace.openLinkText("", normalizedSourcePath, false);
  plugin.app.workspace.onLayoutReady(() => {
    activeWindow.setTimeout(() => {
      scrollToEquationByTag(plugin, tag, normalizedSourcePath).then().catch(console.error);
    }, 50);
  });
}

