var import_obsidian17 = require("obsidian");
init_debugger();
function copyEquationToClipboard(contentWithTag, content, copyType) {
  let textToCopy = "";
  switch (copyType) {
    case "full":
      textToCopy = `$$${contentWithTag}$$`;
      break;
    case "noTag":
      textToCopy = `$$${content}$$`;
      break;
    case "eq":
      textToCopy = content;
      break;
    default:
      textToCopy = `$$${contentWithTag}$$`;
  }
  try {
    const cb = navigator?.clipboard;
    if (!cb?.writeText) throw new Error("navigator.clipboard.writeText unavailable");
    cb.writeText(textToCopy).then(() => new import_obsidian17.Notice("Equation copied to clipboard")).catch((err) => {
      Debugger.error("Failed to copy equation:", err);
      new import_obsidian17.Notice("Failed to copy equation");
    });
  } catch (err) {
    Debugger.error("Failed to copy equation (sync):", err);
    new import_obsidian17.Notice("Failed to copy equation");
  }
}

