// src/ui/panels/equationManagePanel/box_filters.tsx
function boxedEquationFilter(equation, enableTypstMode, skipFirstLine, typstBoxSymbol = "#box") {
  const lines = equation.content.split("\n").map((line) => line.trim()).filter((line) => line.length > 0);
  if (lines.length === 0) return false;
  const lineIndex = skipFirstLine && lines.length > 1 ? 1 : 0;
  const targetLine = lines[lineIndex];
  return enableTypstMode ? targetLine.includes(typstBoxSymbol) : targetLine.includes(String.raw`\boxed`);
}

