async function renderEquationWrapper(plugin, leaf, eq, container, targetComponent, addLinkJump = false) {
  if (!container) {
    Debugger.log("can't find container for equation");
    return;
  }
  const equationWrapper = container.createDiv();
  equationWrapper.addClass("em-equation-wrapper");
  const equationLabelContainer = equationWrapper.createDiv();
  equationLabelContainer.addClass("em-equation-label-container");
  const equationLabel = equationLabelContainer.createDiv();
  equationLabel.addClass("em-equation-label", "em-equation-number");
  equationLabel.textContent = `EQ ${eq.tag || ""}`;
  const fileNameLabel = equationLabelContainer.createDiv();
  fileNameLabel.addClass("em-equation-label", "em-equation-markdown-filename");
  fileNameLabel.textContent = `${eq.filename || ""}`;
  const equationDiv = equationWrapper.createDiv();
  equationDiv.addClass("em-equation-content");
  if (!window.MathJax) await (0, import_obsidian28.loadMathJax)();
  const eqTag = parseEquationTag(eq.md);
  if (plugin.settings.useFastMathRenderer) {
    equationDiv.replaceChildren(window.MathJax.tex2chtml(eqTag.content, { display: true }));
  } else {
    const rendered = (0, import_obsidian28.renderMath)(eqTag.content, true);
    equationDiv.replaceChildren(rendered);
    await (0, import_obsidian28.finishRenderMath)();
  }
  addClickEffects(equationWrapper);
  if (addLinkJump) {
    addClickLinkJump(plugin, equationWrapper, eq, leaf);
  }
  addContextMenuCopy(plugin, equationWrapper, eqTag.contentWithTag, eqTag.content);
}
function addClickEffects(equationWrapper) {
  equationWrapper.addEventListener("click", () => {
    const allEquations = equationWrapper.parentElement?.querySelectorAll(".em-equation-wrapper");
    allEquations?.forEach((eq) => eq.removeClass("em-equation-active"));
    equationWrapper.addClass("em-equation-active");
  });
}
function addClickLinkJump(plugin, equationWrapper, eq, leaf) {
  equationWrapper.addEventListener("dblclick", (event) => {
    if (!eq.sourcePath || !eq.tag) {
      return;
    }
    const view = leaf.view;
    if (!(view instanceof import_obsidian28.MarkdownView)) return;
    const isReadingMode = view.getMode() === "preview";
    if (isReadingMode) {
      new import_obsidian28.Notice("Link jump is not supported in reading mode. Use live preview instead.");
      return;
    }
    const ctrlKey = event.ctrlKey || event.metaKey;
    openFileAndScrollToEquation(
      plugin,
      eq.sourcePath,
      eq.tag,
      ctrlKey,
      // open in split if ctrl key is pressed
      view.leaf
      // current leaf: used for opening when not splitting, or excluded when splitting
    ).then().catch((error) => {
      Debugger.error("Error opening file:", error);
    });
  });
}
function addContextMenuCopy(plugin, equationWrapper, contentWithTag, content) {
  equationWrapper.addEventListener("contextmenu", (event) => {
    event.preventDefault();
    const menu = new import_obsidian28.Menu();
    menu.addItem((item) => {
      item.setTitle("Copy");
      item.setIcon("copy");
      item.onClick(() => {
        const copyType = plugin.settings.equationWidgetRightClickCopyType;
        copyEquationToClipboard(contentWithTag, content, copyType);
      });
    });
    menu.showAtMouseEvent(event);
  });
}

