var import_obsidian29 = require("obsidian");
init_debugger();
var FileSuperScriptPopover = class extends import_obsidian29.HoverPopover {
  constructor(plugin, parent, targetEl, sourcePath, footnoteIndex, waitTime) {
    super(parent, targetEl, waitTime, null);
    this.plugin = plugin;
    this.targetEl = targetEl;
    this.sourcePath = sourcePath;
    this.footnoteIndex = footnoteIndex;
    this.waitTime = waitTime;
  }
  onload() {
    void (async () => {
      const footnotes = await this.plugin.footnoteCache.getFootNotesFromFile(this.sourcePath);
      if (!footnotes) {
        Debugger.log("can't find footnotes for file: ", this.sourcePath);
        return;
      }
      const footnote = footnotes.find((f) => f.num === this.footnoteIndex);
      if (!footnote) {
        Debugger.log("can't find footnote with index: ", this.footnoteIndex, " in file: ", this.sourcePath);
        return;
      }
      this.showFootnote(footnote);
    })().catch((err) => {
      Debugger.error(err);
    });
  }
  onunload() {
  }
  showFootnote(footnote) {
    const container = this.hoverEl.createDiv();
    container.addClass("em-file-superscript-popover-container");
    const footnoteContent = container.createDiv();
    footnoteContent.addClass("em-file-superscript-popover-content");
    if (footnote.path !== null) {
      const filePath = footnote.path;
      const normalizedSourcePath = (0, import_obsidian29.normalizePath)(this.sourcePath);
      const linkEl = footnoteContent.createEl("a", {
        text: footnote.label ?? footnote.path
      });
      linkEl.addClass("em-file-superscript-popover-link");
      linkEl.setAttr("href", footnote.path);
      linkEl.addEventListener("click", (evt) => {
        evt.preventDefault();
        const sourceFile = this.plugin.app.metadataCache.getFirstLinkpathDest(filePath, normalizedSourcePath);
        if (!(sourceFile instanceof import_obsidian29.TFile)) {
          Debugger.log("Invalid footnote file path: ", footnote.path);
          return;
        }
        const newLeaf = evt.ctrlKey || evt.metaKey ? this.plugin.app.workspace.getLeaf("split", "vertical") : this.plugin.app.workspace.getLeaf(true);
        this.plugin.app.workspace.setActiveLeaf(newLeaf, { focus: true });
        this.plugin.app.workspace.openLinkText(
          "",
          sourceFile.path,
          false
        ).then().catch((err) => {
          Debugger.error(err);
        });
      });
    } else if (footnote.url === null) {
      const textEl = footnoteContent.createEl("span", {
        text: footnote.text
      });
      textEl.addClass("em-file-superscript-popover-text");
    } else {
      const linkEl = footnoteContent.createEl("a", {
        text: footnote.label ?? footnote.url
      });
      linkEl.addClass("em-file-superscript-popover-link");
      linkEl.setAttr("href", footnote.url);
    }
  }
};

// src/views/widgets/citation_widget.tsx
var CitationWidget = class extends import_view2.WidgetType {
  constructor(plugin, sourcePath, eqNumbersAll, range) {
    super();
    this.plugin = plugin;
    this.sourcePath = sourcePath;
    this.eqNumbersAll = eqNumbersAll;
    this.range = range;
    this.el = null;
    this.view = null;
    this.popover = null;
    this.parent = null;
    this.plugin = plugin;
  }
  eq(other) {
    return this.eqNumbersAll === other.eqNumbersAll && this.range.from === other.range.from && this.range.to === other.range.to;
  }
  // view is the editor view to create the widget in  
  toDOM(view) {
    this.view = view;
    const parent = this.getMarkdownView();
    const el = renderEquationCitation(
      this.plugin,
      this.sourcePath,
      parent,
      this.eqNumbersAll,
      false
      // need ctrl key to show popover in Live Preview mode 
    );
    this.el = el;
    el.setAttribute("tabindex", "0");
    el.addEventListener("pointerdown", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const setSelectionRange = (view2, from, to) => {
        view2.dispatch({
          selection: import_state2.EditorSelection.range(from, to)
        });
      };
      view.focus();
      setSelectionRange(view, this.range.from, this.range.to);
    });
    this.registerCitaionEvents();
    return el;
  }
  /**
   * reigster events for whole citation part.
   * render equations in once  
   */
  registerCitaionEvents() {
    if (this.el) {
      this.el.addEventListener("mouseenter", (event) => {
        const ctrlKey = event.ctrlKey || event.metaKey;
        if (ctrlKey) {
          void this.showPopover();
        }
      });
    }
  }
  getMarkdownView() {
    const mdView = this.view?.state.field(import_obsidian30.editorInfoField, false);
    return mdView || null;
  }
  /**
   * Show popover with equations preview content. 
   * @returns 
   */
  async showPopover() {
    const parent = this.getMarkdownView();
    if (this.popover !== null) return;
    if (!parent || !this.el) {
      Debugger.error(
        `parent or citationEl is not found for equation citation widget, can't show popover`
      );
      return;
    }
    const sourcePath = this.plugin.app.workspace.getActiveFile()?.path || "";
    const renderedEquations = await this.plugin.equationServices.getEquationsByTags(this.eqNumbersAll, sourcePath);
    if (renderedEquations.length === 0) {
      Debugger.error("No valid equations found for citation widget");
      return;
    }
    this.popover = new CitationPopover(
      this.plugin,
      parent,
      this.el,
      renderedEquations,
      this.plugin.app.workspace.getActiveFile()?.path || "",
      300
    );
    const originalOnClose = this.popover.onClose.bind(this.popover);
    this.popover.onClose = () => {
      originalOnClose();
      this.popover = null;
    };
  }
  ignoreEvent() {
    return false;
  }
};
function renderEquationCitation(plugin, sourcePath, parent, citeEquationTags, isInteractive = false) {
  const {
    enableContinuousCitation,
    enableCrossFileCitation,
    fileCiteDelimiter,
    continuousRangeSymbol,
    continuousDelimiters,
    citationFormat,
    multiCitationDelimiterRender
  } = plugin.settings;
  const el = document.createElement("span");
  const fileDelimiter = enableCrossFileCitation ? fileCiteDelimiter || "^" : DISABLED_DELIMITER;
  const formatedCiteEquationTags = enableContinuousCitation ? combineContinuousCitationTags(
    citeEquationTags,
    continuousRangeSymbol,
    continuousDelimiters.split(" ").filter((d) => d.trim()),
    // remove empty string
    fileDelimiter
  ) : citeEquationTags;
  if (!formatedCiteEquationTags.length) {
    const containerDiv = document.createElement("div");
    containerDiv.addClass("em-math-citation-container");
    const emptyCitationSpanEl = document.createElement("span");
    emptyCitationSpanEl.className = "em-math-citation";
    emptyCitationSpanEl.textContent = citationFormat.replace("#", "");
    containerDiv.appendChild(emptyCitationSpanEl);
    el.appendChild(containerDiv);
    return el;
  }
  const containers = [];
  for (const tag of formatedCiteEquationTags) {
    const containerDiv = document.createElement("div");
    containerDiv.addClass("em-math-citation-container");
    const { local, crossFile } = splitFileCitation(tag, fileDelimiter);
    const citationSpanEl = document.createElement("span");
    citationSpanEl.className = "em-math-citation";
    if (crossFile) {
      const localCitation = citationFormat.replace("#", local);
      citationSpanEl.textContent = localCitation;
      containerDiv.appendChild(citationSpanEl);
      const fileSuperEl = document.createElement("sup");
      fileSuperEl.textContent = `[${crossFile}]`;
      fileSuperEl.className = "em-math-citation-file-superscript";
      if (parent) {
        fileSuperEl.addEventListener("mouseenter", (e) => {
          const ctrlKey = e.ctrlKey || e.metaKey;
          if (isInteractive || ctrlKey) {
            e.preventDefault();
            e.stopPropagation();
            e.stopImmediatePropagation();
            new FileSuperScriptPopover(
              plugin,
              parent,
              fileSuperEl,
              sourcePath,
              crossFile,
              300
            );
          }
        });
      }
      containerDiv.appendChild(fileSuperEl);
    } else {
      citationSpanEl.textContent = citationFormat.replace("#", local);
      containerDiv.appendChild(citationSpanEl);
    }
    containers.push(containerDiv);
    if (multiCitationDelimiterRender && formatedCiteEquationTags.length > 1 && tag !== formatedCiteEquationTags.at(-1)) {
      const multiDelimEl = document.createElement("span");
      multiDelimEl.className = "em-math-citation-multi-delimiter";
      multiDelimEl.textContent = multiCitationDelimiterRender;
      containers.push(multiDelimEl);
    }
  }
  for (const container of containers) {
    el.appendChild(container);
  }
  return el;
}

