// src/views/widgets/figure_citation_render.tsx
init_string_utils();
init_debugger();
function renderFigureCitation(plugin, sourcePath, parent, citeFigureTags, isInteractive = false) {
  const {
    enableContinuousCitation,
    enableCrossFileCitation,
    fileCiteDelimiter,
    continuousRangeSymbol,
    continuousDelimiters,
    multiCitationDelimiterRender
  } = plugin.settings;
  const figureCitationFormat = plugin.settings.figCitationFormat;
  const el = document.createElement("span");
  const fileDelimiter = enableCrossFileCitation ? fileCiteDelimiter || "^" : DISABLED_DELIMITER;
  const formattedCiteFigureTags = enableContinuousCitation ? combineContinuousCitationTags(
    citeFigureTags,
    continuousRangeSymbol,
    continuousDelimiters.split(" ").filter((d) => d.trim()),
    fileDelimiter
  ) : citeFigureTags;
  if (!formattedCiteFigureTags.length) {
    const containerDiv = document.createElement("div");
    containerDiv.addClass("em-math-citation-container");
    containerDiv.addClass("em-figure-citation-container");
    const emptyCitationSpanEl = document.createElement("span");
    emptyCitationSpanEl.className = "em-math-citation em-figure-citation";
    emptyCitationSpanEl.textContent = figureCitationFormat.replace("#", "");
    containerDiv.appendChild(emptyCitationSpanEl);
    el.appendChild(containerDiv);
    return el;
  }
  const containers = [];
  for (const tag of formattedCiteFigureTags) {
    const containerDiv = document.createElement("div");
    containerDiv.addClass("em-math-citation-container");
    containerDiv.addClass("em-figure-citation-container");
    const { local, crossFile } = splitFileCitation(tag, fileDelimiter);
    const citationSpanEl = document.createElement("span");
    citationSpanEl.className = "em-math-citation em-figure-citation";
    if (crossFile) {
      const localCitation = figureCitationFormat.replace("#", local);
      citationSpanEl.textContent = localCitation;
      containerDiv.appendChild(citationSpanEl);
      const fileSuperEl = document.createElement("sup");
      fileSuperEl.textContent = `[${crossFile}]`;
      fileSuperEl.className = "em-math-citation-file-superscript em-figure-citation-file-superscript";
      if (parent) {
        fileSuperEl.addEventListener("mouseenter", (e) => {
          const ctrlKey = e.ctrlKey || e.metaKey;
          if (isInteractive || ctrlKey) {
            e.preventDefault();
            e.stopPropagation();
            e.stopImmediatePropagation();
            new FileSuperScriptPopover(
              plugin,
              parent,
              fileSuperEl,
              sourcePath,
              crossFile,
              300
            );
          }
        });
      }
      containerDiv.appendChild(fileSuperEl);
    } else {
      citationSpanEl.textContent = figureCitationFormat.replace("#", local);
      containerDiv.appendChild(citationSpanEl);
    }
    containers.push(containerDiv);
    if (multiCitationDelimiterRender && formattedCiteFigureTags.length > 1 && tag !== formattedCiteFigureTags.at(-1)) {
      const multiDelimEl = document.createElement("span");
      multiDelimEl.className = "em-math-citation-multi-delimiter em-figure-citation-multi-delimiter";
      multiDelimEl.textContent = multiCitationDelimiterRender;
      containers.push(multiDelimEl);
    }
  }
  for (const container of containers) {
    el.appendChild(container);
  }
  if (parent) {
    el.addEventListener("mouseenter", (event) => {
      const ctrlKey = event.ctrlKey || event.metaKey;
      if (isInteractive || ctrlKey) {
        event.preventDefault();
        event.stopPropagation();
        void showFigurePopover(plugin, parent, el, citeFigureTags, sourcePath);
      }
    });
  }
  return el;
}
async function showFigurePopover(plugin, parent, targetEl, figureTags, sourcePath) {
  try {
    const figures = await plugin.figureServices.getFiguresByTags(figureTags, sourcePath);
    if (figures.length === 0) {
      Debugger.log("No valid figures found for tags:", figureTags);
      return;
    }
    new FigureCitationPopover(
      plugin,
      parent,
      targetEl,
      figures,
      sourcePath,
      300
    );
  } catch (error) {
    Debugger.error("Error showing figure popover:", error);
  }
}

// src/views/widgets/figure_citation_widget.tsx
var FigureCitationWidget = class extends import_view3.WidgetType {
  constructor(plugin, sourcePath, figureTagsAll, range) {
    super();
    this.plugin = plugin;
    this.sourcePath = sourcePath;
    this.figureTagsAll = figureTagsAll;
    this.range = range;
    this.el = null;
    this.view = null;
    this.popover = null;
  }
  eq(other) {
    return this.figureTagsAll === other.figureTagsAll && this.range.from === other.range.from && this.range.to === other.range.to;
  }
  toDOM(view) {
    this.view = view;
    const parent = this.getMarkdownView();
    const el = renderFigureCitation(
      this.plugin,
      this.sourcePath,
      parent,
      this.figureTagsAll,
      false
      // need ctrl key to show popover in Live Preview mode
    );
    this.el = el;
    el.setAttribute("tabindex", "0");
    el.addEventListener("pointerdown", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const setSelectionRange = (view2, from, to) => {
        view2.dispatch({
          selection: import_state3.EditorSelection.range(from, to)
        });
      };
      view.focus();
      setSelectionRange(view, this.range.from, this.range.to);
    });
    this.registerCitationEvents();
    return el;
  }
  /**
   * Register events for the figure citation
   * Render figures on hover with Ctrl key
   */
  registerCitationEvents() {
    if (this.el) {
      this.el.addEventListener("mouseenter", (event) => {
        const ctrlKey = event.ctrlKey || event.metaKey;
        if (ctrlKey) {
          void this.showPopover();
        }
      });
    }
  }
  getMarkdownView() {
    const mdView = this.view?.state.field(import_obsidian32.editorInfoField, false);
    return mdView || null;
  }
  /**
   * Show popover with figure preview content
   */
  async showPopover() {
    const parent = this.getMarkdownView();
    if (this.popover !== null) return;
    if (!parent || !this.el) {
      Debugger.error(`parent is not equal with citationEl, can't show popover`);
      return;
    }
    const sourcePath = this.plugin.app.workspace.getActiveFile()?.path || "";
    const renderedFigures = await this.plugin.figureServices.getFiguresByTags(this.figureTagsAll, sourcePath);
    if (renderedFigures.length === 0) {
      Debugger.log(`No valid figures found for citation: ${this.figureTagsAll.join(", ")}`);
      new import_obsidian32.Notice(`Figure not found: fig:${this.figureTagsAll.join(", ")}`);
      return;
    }
    this.popover = new FigureCitationPopover(
      this.plugin,
      parent,
      this.el,
      renderedFigures,
      this.plugin.app.workspace.getActiveFile()?.path || "",
      300
    );
    const originalOnClose = this.popover.onClose.bind(this.popover);
    this.popover.onClose = () => {
      originalOnClose();
      this.popover = null;
    };
  }
  ignoreEvent() {
    return false;
  }
};

