function resolveBackLinks(links, targetFile) {
  if (!links || !targetFile) {
    return [];
  }
  const backLinks = [];
  for (const [sourceFile, outLinks] of Object.entries(links)) {
    if (outLinks && typeof outLinks === "object") {
      if (targetFile in outLinks) {
        backLinks.push(sourceFile);
      }
    }
  }
  return backLinks;
}

